Implement SEO components for the Astro project.

Working directory: /Users/so/MyWorkSpace/personal/care-inomi/.worktrees/feature/initial-setup

1. Create src/components/seo/SEOHead.astro:

```astro
---
import type { SEOProps } from "../../types/content";
import { SITE_CONFIG } from "../../lib/constants";

interface Props extends SEOProps {}

const {
  title,
  description,
  ogImage,
  ogType = "website",
  noIndex = false,
  canonicalUrl,
} = Astro.props;

const siteUrl = SITE_CONFIG.url;
const resolvedCanonicalUrl = canonicalUrl || new URL(Astro.url.pathname, siteUrl).href;
const resolvedOgImage = ogImage ? new URL(ogImage, siteUrl).href : undefined;
const fullTitle = title.includes(SITE_CONFIG.name) ? title : `${title} | ${SITE_CONFIG.name}`;
---

<!-- Primary Meta Tags -->
<title>{fullTitle}</title>
<meta name="title" content={fullTitle} />
<meta name="description" content={description} />
<link rel="canonical" href={resolvedCanonicalUrl} />
{noIndex && <meta name="robots" content="noindex, nofollow" />}

<!-- Open Graph / Facebook -->
<meta property="og:type" content={ogType} />
<meta property="og:url" content={resolvedCanonicalUrl} />
<meta property="og:title" content={fullTitle} />
<meta property="og:description" content={description} />
{resolvedOgImage && <meta property="og:image" content={resolvedOgImage} />}
<meta property="og:locale" content={SITE_CONFIG.locale} />
<meta property="og:site_name" content={SITE_CONFIG.name} />

<!-- Twitter -->
<meta name="twitter:card" content="summary_large_image" />
<meta name="twitter:url" content={resolvedCanonicalUrl} />
<meta name="twitter:title" content={fullTitle} />
<meta name="twitter:description" content={description} />
{resolvedOgImage && <meta name="twitter:image" content={resolvedOgImage} />}
```

2. Create src/components/seo/StructuredData.astro:

```astro
---
import { SITE_CONFIG, COMPANY_INFO } from "../../lib/constants";

interface Props {
  type: "Organization" | "LocalBusiness" | "FAQPage" | "WebSite";
  data?: Record<string, unknown>;
}

const { type, data = {} } = Astro.props;

const baseOrganization = {
  "@context": "https://schema.org",
  "@type": "Organization",
  name: COMPANY_INFO.name,
  url: SITE_CONFIG.url,
  logo: `${SITE_CONFIG.url}/images/logo.png`,
  description: SITE_CONFIG.description,
  address: {
    "@type": "PostalAddress",
    addressCountry: "JP",
    addressRegion: "東京都",
  },
  ...data,
};

const webSite = {
  "@context": "https://schema.org",
  "@type": "WebSite",
  name: SITE_CONFIG.name,
  url: SITE_CONFIG.url,
  ...data,
};

const localBusiness = {
  "@context": "https://schema.org",
  "@type": "LocalBusiness",
  name: COMPANY_INFO.name,
  url: SITE_CONFIG.url,
  ...data,
};

const faqPage = {
  "@context": "https://schema.org",
  "@type": "FAQPage",
  mainEntity: data.questions?.map((q: { question: string; answer: string }) => ({
    "@type": "Question",
    name: q.question,
    acceptedAnswer: {
      "@type": "Answer",
      text: q.answer,
    },
  })) || [],
};

const schemas: Record<string, object> = {
  Organization: baseOrganization,
  LocalBusiness: localBusiness,
  FAQPage: faqPage,
  WebSite: webSite,
};

const schema = schemas[type];
---

<script type="application/ld+json" set:html={JSON.stringify(schema)} />
```

Use Write tool to create both files.

